    // ── Public API ────────────────────────────────────────────────────────────

    /**
     * Returns the [GlobalEvent] for the given [date].
     * Falls back to a safe placeholder if the key is somehow missing.
     */
    fun getEventForDate(date: LocalDate): GlobalEvent {
        val key = date.format(formatter)
        return events[key] ?: GlobalEvent(
            title = "Global Event",
            description = "Today is a day to celebrate and reflect."
        )
    }

    /**
     * Returns today's [GlobalEvent] using the real calendar date.
     * Stable for the entire calendar day — no random selection.
     */
    fun getTodayEvent(): GlobalEvent = getEventForDate(LocalDate.now())

    /**
     * Returns only the title of tomorrow's event.
     * Handles year wrap: December 31 → January 1.
     */
    fun getTomorrowTitle(): String {
        val tomorrow = LocalDate.now().plusDays(1)
        return getEventForDate(tomorrow).title
    }
}
